import { useEffect, useState, useCallback } from "react";
import "./HackerDashboard.scss";

export default function HackerDashboard() {
  const [role, setRole] = useState("");
  const [username, setUsername] = useState("");
  const [bugs, setBugs] = useState([]);

  const token = localStorage.getItem("token");

  // 🔥 FETCH BUGS (MEMOIZED)
  const fetchBugs = useCallback(() => {
    if (!token) return;

    fetch("http://localhost:5000/api/bugs/hacker/bugs", {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setBugs(data.bugs || []))
      .catch((err) => console.error("BUG FETCH ERROR:", err));
  }, [token]);

  useEffect(() => {
    const storedRole = localStorage.getItem("role");
    const storedUser = localStorage.getItem("username");

    // 🔒 Auth guard
    if (!token) {
      window.location.href = "/";
      return;
    }

    setRole(storedRole || "");
    if (storedUser) setUsername(storedUser);

    fetchBugs();
  }, [fetchBugs, token]);

  // 🔢 COUNTS
  const submittedCount = bugs.filter((b) => b.status === "submitted").length;
  const approvedCount = bugs.filter((b) => b.status === "approved").length;
  const rejectedCount = bugs.filter((b) => b.status === "rejected").length;

  // 💰 TOTAL REWARDS
  const totalRewards = bugs
    .filter((b) => b.status === "approved")
    .reduce((sum, b) => sum + (b.reward || 0), 0);

  return (
    <div className="hacker-dashboard">
      {/* HEADER */}
      <header className="dashboard-header">
        <div>
          <h1>
            <span className="neon">🧑‍💻 Hacker Dashboard</span>
          </h1>
          <p className="muted">
            Logged in as <span className="highlight">@{username}</span> | Role:{" "}
            <span className="role">{role}</span>
          </p>
        </div>

        <div className="status">
          <span className="dot"></span> ONLINE
        </div>
      </header>

      {/* STATS */}
      <section className="stats-grid">
        <div
          className="stat-card"
          onClick={() => (window.location.href = "/my-bugs?status=submitted")}
        >
          <h3>🐞 Bugs Submitted</h3>
          <p>{submittedCount}</p>
        </div>

        <div
          className="stat-card"
          onClick={() => (window.location.href = "/my-bugs?status=approved")}
        >
          <h3>✅ Approved</h3>
          <p>{approvedCount}</p>
        </div>

        <div
          className="stat-card"
          onClick={() => (window.location.href = "/my-bugs?status=rejected")}
        >
          <h3>❌ Rejected</h3>
          <p>{rejectedCount}</p>
        </div>

        <div className="stat-card reward-card">
          <h3>💰 Total Rewards</h3>
          <p>₹{totalRewards}</p>
        </div>
      </section>

      {/* ACTIONS */}
      <section className="actions-grid">
        <div
          className="action-card"
          onClick={() => (window.location.href = "/submit-bug")}
        >
          <h2>🐞 Submit Bug</h2>
          <p>Report a new vulnerability</p>
        </div>

        <div
          className="action-card"
          onClick={() => (window.location.href = "/my-bugs")}
        >
          <h2>📄 My Bugs</h2>
          <p>Track submissions & status</p>
        </div>

        <div
          className="action-card"
          onClick={() => (window.location.href = "/wallet")}
        >
          <h2>💰 Wallet</h2>
          <p>Rewards & payouts</p>
        </div>
      </section>

      {/* TERMINAL */}
      <section className="terminal">
        <p>[✓] Connected to bounty network</p>
        <p>[✓] Bugs loaded: {bugs.length}</p>
        <span className="cursor">█</span>
      </section>

      {/* LOGOUT */}
      <button
        className="logout-btn"
        onClick={() => {
          localStorage.clear();
          window.location.href = "/";
        }}
      >
        🔒 Logout
      </button>
    </div>
  );
}
